form:Form.form:Scripts:
		function deshabilitarControles()
{
	//Valido que no se pueda eliminar los tipos de evaluaciones Individual o gerencial en el modo LIST del form
	if (Ctrl('main').GetMode()=="LIST")
	{
		if (Ctrl('LIST').GetSelectAttrValue('c_tipo_eval') == 'GER' || Ctrl('LIST').GetSelectAttrValue('c_tipo_eval') == 'IND')
	  {
			CtrlEnabled('DELETE',false);
		}
		else
		{
			CtrlEnabled('DELETE',true);
		}
	}
	else
	//Valido que no se pueda eliminar los tipos de evaluaciones Individual o gerencial en los modos EDIT/SHOW del form
	{
		if (Ctrl('c_tipo_eval').GetXValue() == 'GER' || Ctrl('c_tipo_eval').GetXValue() == 'IND')
	  {
			CtrlEnabled('DELETE',false);
			CtrlEnabled('c_tipo_eval',false);
			CtrlEnabled('d_tipo_eval',false);
		}
		else
		{
			CtrlEnabled('DELETE',true);
			CtrlEnabled('c_tipo_eval',true);
			CtrlEnabled('d_tipo_eval',true); 	
		}
	}
}
